            @(IsValidating ? "Validating..." : "Next")
        </button>
    </div>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public EventCallback<(string FullName, string Email, string Phone, string Address)> OnNext { get; set; }
    [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }

    private string? ErrorMessage;
    private bool IsValidating;

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(FullName))
        {
            ErrorMessage = "Full name is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(Email))
        {
            ErrorMessage = "Email is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(Phone))
        {
            ErrorMessage = "Phone is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(Address))
        {
            ErrorMessage = "Address is required.";
            return;
        }

        if (ValidateEmail is not null)
        {
            IsValidating = true;
            StateHasChanged();
            var isValid = await ValidateEmail(Email);
            IsValidating = false;
            if (!isValid)
            {
                ErrorMessage = "Please enter a valid email address.";
                return;
            }
        }

        await OnNext.InvokeAsync((FullName, Email, Phone, Address));
    }
}
