@namespace sv_1c7d72802c834b1ab5ecfa90b5ad5307.Components.Pages.Apply

<div class="step-indicator">
    @for (int i = 0; i < StepNames.Count; i++)
    {
        var stepIndex = i;
        var stepClass = GetStepClass(stepIndex);
        <div class="step @stepClass" @onclick="() => OnStepClick(stepIndex)">
            <div class="step-circle">
                @if (stepIndex < CurrentStep)
                {
                    <span class="checkmark">&#10003;</span>
                }
                else
                {
                    <span>@(stepIndex + 1)</span>
                }
            </div>
            <div class="step-label">@StepNames[stepIndex]</div>
        </div>
        @if (stepIndex < StepNames.Count - 1)
        {
            <div class="step-connector @(stepIndex < CurrentStep ? "completed" : "")"></div>
        }
    }
</div>

@code {
    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnStepSelected { get; set; }

    private static readonly List<string> StepNames = new()
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    private string GetStepClass(int step)
    {
        if (step == CurrentStep) return "active";
        if (step < CurrentStep) return "completed";
        return "dimmed";
    }

    private async Task OnStepClick(int step)
    {
        if (step < CurrentStep)
        {
            await OnStepSelected.InvokeAsync(step);
        }
    }
}

