@namespace sv_1c7d72802c834b1ab5ecfa90b5ad5307.Components.Pages.Apply

<div class="step-content">
    <h3>Personal Information</h3>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="validation-error">@ErrorMessage</div>
    }

    <div class="form-group">
        <label for="fullName">Full Name *</label>
        <input id="fullName" type="text" @bind="FullName" @bind:event="oninput" placeholder="Enter your full name" />
    </div>

    <div class="form-group">
        <label for="email">Email *</label>
        <input id="email" type="email" @bind="Email" @bind:event="oninput" placeholder="Enter your email" />
    </div>

    <div class="form-group">
        <label for="phone">Phone *</label>
        <input id="phone" type="tel" @bind="Phone" @bind:event="oninput" placeholder="Enter your phone number" />
    </div>

    <div class="form-group">
        <label for="address">Address *</label>
        <textarea id="address" @bind="Address" @bind:event="oninput" placeholder="Enter your address"></textarea>
    </div>

    <div class="step-buttons">
        <button class="btn-next" @onclick="HandleNext" disabled="@IsValidating">
            @(IsValidating ? "Validating..." : "Next")
        </button>
    </div>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public EventCallback<(string FullName, string Email, string Phone, string Address)> OnNext { get; set; }
    [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }

    private string? ErrorMessage;
    private bool IsValidating;

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(FullName))
        {
            ErrorMessage = "Full name is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(Email))
        {
            ErrorMessage = "Email is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(Phone))
        {
            ErrorMessage = "Phone is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(Address))
        {
            ErrorMessage = "Address is required.";
            return;
        }

        if (ValidateEmail is not null)
        {
            IsValidating = true;
            StateHasChanged();
            var isValid = await ValidateEmail(Email);
            IsValidating = false;
            if (!isValid)
            {
                ErrorMessage = "Please enter a valid email address.";
                return;
            }
        }

        await OnNext.InvokeAsync((FullName, Email, Phone, Address));
    }
}

