@namespace sv_1c7d72802c834b1ab5ecfa90b5ad5307.Components.Pages.Apply

<div class="work-entry-form">
    <div class="entry-header">
        <h4>Position @(Index + 1)</h4>
        @if (CanRemove)
        {
            <button class="btn-remove" @onclick="() => OnRemove.InvokeAsync(Index)">Remove</button>
        }
    </div>

    <div class="form-group">
        <label>Company Name *</label>
        <input type="text" value="@Entry.Company" @onchange="e => UpdateEntry(company: e.Value?.ToString())" />
    </div>

    <div class="form-group">
        <label>Job Title *</label>
        <input type="text" value="@Entry.Title" @onchange="e => UpdateEntry(title: e.Value?.ToString())" />
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Start Date *</label>
            <input type="date" value="@Entry.StartDate.ToString("yyyy-MM-dd")" @onchange="e => UpdateEntry(startDate: DateTime.TryParse(e.Value?.ToString(), out var d) ? d : Entry.StartDate)" />
        </div>

        <div class="form-group">
            <label>End Date</label>
            <input type="date" value="@Entry.EndDate?.ToString("yyyy-MM-dd")" @onchange="e => UpdateEntry(endDate: DateTime.TryParse(e.Value?.ToString(), out var d) ? d : null)" disabled="@IsCurrent" />
            <label class="checkbox-label">
                <input type="checkbox" checked="@IsCurrent" @onchange="HandleCurrentToggle" />
                Currently working here
            </label>
        </div>
    </div>

    <div class="form-group">
        <label>Description</label>
        <textarea value="@Entry.Description" @onchange="e => UpdateEntry(description: e.Value?.ToString())"></textarea>
    </div>
</div>

@code {
    [Parameter] public WorkEntryModel Entry { get; set; } = new();
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback<(int Index, WorkEntryModel Entry)> OnEntryChanged { get; set; }
    [Parameter] public EventCallback<int> OnRemove { get; set; }

    private bool IsCurrent => Entry.EndDate is null && Entry.IsCurrent;

    private async Task UpdateEntry(string? company = null, string? title = null, DateTime? startDate = null, DateTime? endDate = null, string? description = null)
    {
        var updated = Entry with
        {
            Company = company ?? Entry.Company,
            Title = title ?? Entry.Title,
            StartDate = startDate ?? Entry.StartDate,
            EndDate = endDate ?? Entry.EndDate,
            Description = description ?? Entry.Description
        };
        await OnEntryChanged.InvokeAsync((Index, updated));
    }

    private async Task HandleCurrentToggle(ChangeEventArgs e)
    {
        var isCurrent = (bool)(e.Value ?? false);
