@namespace sv_1c7d72802c834b1ab5ecfa90b5ad5307.Components.Pages.Apply

<div class="step-content">
    <h3>Work History</h3>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="validation-error">@ErrorMessage</div>
    }

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryForm Entry="@Entries[index]"
                       Index="@index"
                       CanRemove="@(Entries.Count > 1)"
                       OnEntryChanged="HandleEntryChanged"
                       OnRemove="HandleRemove" />
    }

    <button class="btn-add" @onclick="AddEntry">+ Add Another Position</button>

    <div class="step-buttons">
        <button class="btn-back" @onclick="OnBack">Back</button>
        <button class="btn-next" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public List<WorkEntryForm.WorkEntryModel> Entries { get; set; } = new();
    [Parameter] public EventCallback<List<WorkEntryForm.WorkEntryModel>> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryForm.WorkEntryModel());
        StateHasChanged();
    }

    private void HandleRemove(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
            StateHasChanged();
        }
    }

    private void HandleEntryChanged((int Index, WorkEntryForm.WorkEntryModel Entry) args)
    {
        Entries[args.Index] = args.Entry;
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                ErrorMessage = "Each position must have a company name and job title.";
                return;
            }
        }

        await OnNext.InvokeAsync(Entries);
    }
}

