@namespace sv_1c7d72802c834b1ab5ecfa90b5ad5307.Components.Pages.Apply

<div class="reference-form">
    <div class="entry-header">
        <h4>Reference @(Index + 1)</h4>
        @if (CanRemove)
        {
            <button class="btn-remove" @onclick="() => OnRemove.InvokeAsync(Index)">Remove</button>
        }
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Name *</label>
            <input type="text" value="@Entry.Name" @onchange="e => UpdateEntry(name: e.Value?.ToString())" />
        </div>

        <div class="form-group">
            <label>Relationship *</label>
            <input type="text" value="@Entry.Relationship" @onchange="e => UpdateEntry(relationship: e.Value?.ToString())" />
        </div>
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Email *</label>
            <input type="email" value="@Entry.Email" @onchange="e => UpdateEntry(email: e.Value?.ToString())" />
        </div>

        <div class="form-group">
            <label>Phone *</label>
            <input type="tel" value="@Entry.Phone" @onchange="e => UpdateEntry(phone: e.Value?.ToString())" />
        </div>
    </div>
</div>

@code {
    [Parameter] public ReferenceModel Entry { get; set; } = new();
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback<(int Index, ReferenceModel Entry)> OnEntryChanged { get; set; }
    [Parameter] public EventCallback<int> OnRemove { get; set; }

    private async Task UpdateEntry(string? name = null, string? relationship = null, string? email = null, string? phone = null)
    {
        var updated = Entry with
        {
            Name = name ?? Entry.Name,
            Relationship = relationship ?? Entry.Relationship,
            Email = email ?? Entry.Email,
            Phone = phone ?? Entry.Phone
        };
        await OnEntryChanged.InvokeAsync((Index, updated));
    }

    public record ReferenceModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }
}

@namespace sv_1c7d72802c834b1ab5ecfa90b5ad5307.Components.Pages.Apply

<div class="step-content">
    <h3>References</h3>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="validation-error">@ErrorMessage</div>
    }

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        <ReferenceForm Entry="@References[index]"
                       Index="@index"
                       CanRemove="@(References.Count > 2)"
                       OnEntryChanged="HandleEntryChanged"
                       OnRemove="HandleRemove" />
    }

    @if (References.Count < 3)
    {
        <button class="btn-add" @onclick="AddReference">+ Add Reference</button>
    }

    <div class="step-buttons">
        <button class="btn-back" @onclick="OnBack">Back</button>
        <button class="btn-next" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public List<ReferenceForm.ReferenceModel> References { get; set; } = new();
    [Parameter] public EventCallback<List<ReferenceForm.ReferenceModel>> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new ReferenceForm.ReferenceModel());
            StateHasChanged();
        }
    }

    private void HandleRemove(int index)
    {
        if (References.Count > 2)
        {
            References.RemoveAt(index);
            StateHasChanged();
        }
    }

    private void HandleEntryChanged((int Index, ReferenceForm.ReferenceModel Entry) args)
    {
        References[args.Index] = args.Entry;
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var reference in References)
        {
            if (string.IsNullOrWhiteSpace(reference.Name) || string.IsNullOrWhiteSpace(reference.Relationship)
                || string.IsNullOrWhiteSpace(reference.Email) || string.IsNullOrWhiteSpace(reference.Phone))
            {
                ErrorMessage = "All reference fields are required.";
                return;
            }
        }

        await OnNext.InvokeAsync(References);
    }
}

