@namespace sv_1c7d72802c834b1ab5ecfa90b5ad5307.Components.Pages.Apply

<div class="step-content">
    <h3>Cover Letter</h3>

    <div class="form-group">
        <label for="coverLetter">Write your cover letter</label>
        <textarea id="coverLetter" class="cover-letter-textarea" @bind="CoverLetter" @bind:event="oninput"
                  maxlength="2000" placeholder="Tell us why you're a great fit for this position..."></textarea>
        <div class="char-count @(CoverLetter.Length > 1800 ? "warning" : "")">
            @CoverLetter.Length / 2000 characters
        </div>
    </div>

    <div class="step-buttons">
        <button class="btn-back" @onclick="OnBack">Back</button>
        <button class="btn-next" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private async Task HandleNext()
    {
        await OnNext.InvokeAsync(CoverLetter);
    }
}

@namespace sv_1c7d72802c834b1ab5ecfa90b5ad5307.Components.Pages.Apply

<div class="step-content">
    <h3>Review & Submit</h3>

    @if (IsSubmitted)
    {
        <div class="submission-confirmation">
            <h4>&#10003; Application Submitted Successfully!</h4>
            <p>Your application ID is: <strong>@ApplicationId</strong></p>
            <p>Thank you for applying. We will review your application and get back to you.</p>
        </div>
    }
    else
    {
        @if (!string.IsNullOrEmpty(ErrorMessage))
        {
            <div class="validation-error">@ErrorMessage</div>
        }

        <div class="review-section">
            <div class="review-header">
                <h4>Personal Information</h4>
                <button class="btn-edit" @onclick="() => OnEditSection.InvokeAsync(0)">Edit</button>
            </div>
            <dl>
                <dt>Name</dt><dd>@FullName</dd>
                <dt>Email</dt><dd>@Email</dd>
                <dt>Phone</dt><dd>@Phone</dd>
                <dt>Address</dt><dd>@Address</dd>
            </dl>
        </div>

        <div class="review-section">
            <div class="review-header">
                <h4>Work History</h4>
                <button class="btn-edit" @onclick="() => OnEditSection.InvokeAsync(1)">Edit</button>
            </div>
            @foreach (var entry in WorkEntries)
            {
                <div class="review-entry">
                    <strong>@entry.Title</strong> at @entry.Company
                    <br />
                    <span class="date-range">
                        @entry.StartDate.ToString("MMM yyyy") &ndash;
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                    </span>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p>@entry.Description</p>
                    }
                </div>
            }
        </div>

        <div class="review-section">
            <div class="review-header">
                <h4>References</h4>
                <button class="btn-edit" @onclick="() => OnEditSection.InvokeAsync(2)">Edit</button>
            </div>
            @foreach (var reference in References)
            {
                <div class="review-entry">
                    <strong>@reference.Name</strong> (@reference.Relationship)
                    <br />
                    @reference.Email &bull; @reference.Phone
                </div>
            }
        </div>

        <div class="review-section">
            <div class="review-header">
                <h4>Cover Letter</h4>
                <button class="btn-edit" @onclick="() => OnEditSection.InvokeAsync(3)">Edit</button>
            </div>
            <p class="cover-letter-preview">@CoverLetter</p>
        </div>

        <div class="step-buttons">
            <button class="btn-back" @onclick="OnBack">Back</button>
            <button class="btn-submit" @onclick="HandleSubmit" disabled="@IsSubmitting">
                @(IsSubmitting ? "Submitting..." : "Submit Application")
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public List<WorkEntryForm.WorkEntryModel> WorkEntries { get; set; } = new();
    [Parameter] public List<ReferenceForm.ReferenceModel> References { get; set; } = new();
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEditSection { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }

    public bool IsSubmitting { get; set; }
    public bool IsSubmitted { get; set; }
    public int? ApplicationId { get; set; }
    public string? ErrorMessage { get; set; }

    public void SetSubmitting(bool submitting)
    {
        IsSubmitting = submitting;
        StateHasChanged();
    }

    public void SetSubmitted(int applicationId)
    {
        IsSubmitted = true;
        ApplicationId = applicationId;
        IsSubmitting = false;
        StateHasChanged();
    }

    public void SetError(string error)
    {
        ErrorMessage = error;
        IsSubmitting = false;
        StateHasChanged();
    }

    private async Task HandleSubmit()
    {
        await OnSubmit.InvokeAsync();
    }
}

