toolArgs.file_text:
@page "/apply"
@using sv_1c7d72802c834b1ab5ecfa90b5ad5307.Components.Pages.Apply
@using sv_1c7d72802c834b1ab5ecfa90b5ad5307.Models
@using sv_1c7d72802c834b1ab5ecfa90b5ad5307.Services
@inject IApplicationService ApplicationService
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="apply-page">
    <h2>Job Application</h2>

    <StepIndicator CurrentStep="@_currentStep" OnStepSelected="GoToStep" />

    @switch (_currentStep)
    {
        case 0:
            <PersonalInfoStep FullName="@_fullName"
                              Email="@_email"
                              Phone="@_phone"
                              Address="@_address"
                              ValidateEmail="ApplicationService.ValidateEmailAsync"
                              OnNext="HandlePersonalInfoNext" />
            break;
        case 1:
            <WorkHistoryStep Entries="@_workEntries"
                             OnNext="HandleWorkHistoryNext"
                             OnBack="GoBack" />
            break;
        case 2:
            <ReferencesStep References="@_references"
                            OnNext="HandleReferencesNext"
                            OnBack="GoBack" />
            break;
        case 3:
            <CoverLetterStep CoverLetter="@_coverLetter"
                             OnNext="HandleCoverLetterNext"
                             OnBack="GoBack" />
            break;
        case 4:
            <ReviewStep @ref="_reviewStep"
                        FullName="@_fullName"
                        Email="@_email"
                        Phone="@_phone"
                        Address="@_address"
                        WorkEntries="@_workEntries"
                        References="@_references"
                        CoverLetter="@_coverLetter"
                        OnEditSection="GoToStep"
                        OnBack="GoBack"
                        OnSubmit="HandleSubmit" />
            break;
    }
</div>

@code {
    private int _currentStep;
    private ReviewStep? _reviewStep;

    // Step 1 data
    private string _fullName = "";
    private string _email = "";
    private string _phone = "";
    private string _address = "";

    // Step 2 data
    private List<WorkEntryForm.WorkEntryModel> _workEntries = new() { new() };

    // Step 3 data
    private List<ReferenceForm.ReferenceModel> _references = new() { new(), new() };

    // Step 4 data
    private string _coverLetter = "";

    private void GoToStep(int step)
    {
        _currentStep = step;
    }

    private void GoBack()
    {
        if (_currentStep > 0) _currentStep--;
    }

    private void HandlePersonalInfoNext((string FullName, string Email, string Phone, string Address) data)
    {
        _fullName = data.FullName;
        _email = data.Email;
        _phone = data.Phone;
        _address = data.Address;
        _currentStep = 1;
    }

    private void HandleWorkHistoryNext(List<WorkEntryForm.WorkEntryModel> entries)
    {
        _workEntries = entries;
        _currentStep = 2;
    }

    private void HandleReferencesNext(List<ReferenceForm.ReferenceModel> references)
    {
        _references = references;
        _currentStep = 3;
    }

    private void HandleCoverLetterNext(string coverLetter)
    {
        _coverLetter = coverLetter;
        _currentStep = 4;
    }

    private async Task HandleSubmit()
    {
        _reviewStep?.SetSubmitting(true);

        try
        {
            var application = new JobApplication(
                new PersonalInfo(_fullName, _email, _phone, _address),
                new WorkHistory(_workEntries.Select(e => new WorkEntry(
                    e.Company, e.Title, e.StartDate, e.EndDate, e.Description)).ToList()),
                _references.Select(r => new Reference(
                    r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
                _coverLetter
            );

            var id = await ApplicationService.SubmitApplicationAsync(application);
            _reviewStep?.SetSubmitted(id);
        }
        catch (Exception ex)
        {
            _reviewStep?.SetError($"Submission failed: {ex.Message}");
        }
    }
}

